-- Create indexes
CREATE INDEX idx_emp_salary  ON employees (salary);
CREATE INDEX idx_emp_dept    ON employees (dept_id);
CREATE UNIQUE INDEX idx_emp_email ON employees (email);

-- Composite index (column order matters!)
CREATE INDEX idx_emp_dept_salary ON employees (dept_id, salary);

-- Check if index is being used (EXPLAIN)
EXPLAIN SELECT * FROM employees WHERE dept_id = 10 AND salary > 70000;
-- Good: type=range, key=idx_emp_dept_salary
-- Bad:  type=ALL (full table scan)

-- Covering index: query uses only indexed columns
SELECT dept_id, salary FROM employees WHERE dept_id = 10;
-- MySQL reads ONLY the index, never touches the main table!

-- When indexes HURT performance:
-- 1. NOT operator:  WHERE salary != 50000  (can't use index efficiently)
-- 2. Leading wildcard: WHERE name LIKE '%Alice'  (no B-tree traversal)
-- 3. Function on column: WHERE YEAR(hire_date) = 2023
--    Use range instead: WHERE hire_date BETWEEN '2023-01-01' AND '2023-12-31'

DROP INDEX idx_emp_salary ON employees;
